mapper.select:
SELECT s.student_id, s.user_id, s.student_number, u.real_name, u.gender, oc.org_name AS college_name, ok.org_name AS class_name, s.grade, u.phone, u.email FROM student_info s LEFT JOIN user u ON u.user_id = s.user_id LEFT JOIN organization oc ON oc.org_id = s.college_id LEFT JOIN organization ok ON ok.org_id = s.class_id
AND (s.student_number LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%'))
AND s.college_id = #{collegeId}
AND s.class_id = #{classId}
AND s.grade = #{grade}
ORDER BY s.student_number ASC
